Q = 3329

def encode_message(m: bytes) -> list:
    """Encode 32-byte message to polynomial coefficients."""
    bits = []
    for byte in m:
        for i in range(8):
            bits.append((byte >> i) & 1)
    return [0 if b == 0 else Q // 2 for b in bits]

def add_noise(coefficients: list, max_noise: int) -> list:
    """Add random noise to coefficients."""
    import random
    noisy = []
    for c in coefficients:
        noise = random.randint(-max_noise, max_noise)
        noisy.append((c + noise) % Q)
    return noisy

